mapper.select:
SELECT id, batch_id, user_id, created_by, reservation_mode, device_id, start_time, end_time, purpose, status, approval_mode_snapshot, remark, device_approver_id, device_approved_at, device_approval_remark, system_approver_id, system_approved_at, system_approval_remark, sign_status, checked_in_at, cancel_reason, cancel_time, created_at, updated_at FROM reservation WHERE 1 = 1
AND user_id = #{userId}
ORDER BY created_at DESC, start_time DESC LIMIT #{limit} OFFSET #{offset}

SELECT id, batch_id, user_id, created_by, reservation_mode, device_id, start_time, end_time, purpose, status,
       approval_mode_snapshot, remark, device_approver_id, device_approved_at, device_approval_remark,
       system_approver_id, system_approved_at, system_approval_remark, sign_status, checked_in_at,
       cancel_reason, cancel_time, created_at, updated_at
FROM reservation
WHERE device_id = #{deviceId}
  AND status IN ('PENDING_DEVICE_APPROVAL', 'PENDING_SYSTEM_APPROVAL', 'PENDING_MANUAL', 'APPROVED')
  AND start_time < #{endTime}
  AND end_time > #{startTime}

SELECT COUNT(1)
FROM reservation
WHERE device_id = #{deviceId}
  AND status IN ('PENDING_DEVICE_APPROVAL', 'PENDING_SYSTEM_APPROVAL', 'PENDING_MANUAL', 'APPROVED')
  AND start_time < #{endTime}
  AND end_time > #{startTime}

mapper.update:
UPDATE reservation
SET status = 'CANCELLED',
    cancel_reason = #{cancelReason},
    cancel_time = #{cancelTime},
    updated_at = #{updatedAt}
WHERE id = #{reservationId}
  AND status IN

      #{status}

  AND sign_status = 'NOT_CHECKED_IN'
  AND checked_in_at IS NULL
  AND start_time > #{currentTime}
